SELECT 
FROM device_instance d
LEFT JOIN device_model m ON m.id = d.model_id AND m.deleted = 0
LEFT JOIN project p ON p.id = d.project_id AND p.deleted = 0
LEFT JOIN warehouse w ON w.id = d.warehouse_id AND w.deleted = 0

    d.deleted = 0

        AND (d.serial_number LIKE CONCAT('%', #{query.keyword}, '%')
          OR d.mac_address LIKE CONCAT('%', #{query.keyword}, '%'))


        AND d.status = #{query.status}


        AND d.model_id = #{query.modelId}


        AND d.project_id = #{query.projectId}


        AND d.warehouse_id = #{query.warehouseId}


        AND d.agent_company_id = #{query.agentCompanyId}


        AND d.site_name LIKE CONCAT('%', #{query.siteName}, '%')


ORDER BY d.create_time DESC, d.id DESC

SELECT status, COUNT(*) AS cnt FROM device_instance WHERE deleted = 0
AND project_id = #{projectId}
GROUP BY status

SELECT d.model_id AS modelId, m.model_name AS modelName, m.model_code AS modelCode, COUNT(*) AS cnt FROM device_instance d LEFT JOIN device_model m ON m.id = d.model_id AND m.deleted = 0 WHERE d.deleted = 0
AND d.project_id = #{projectId}
GROUP BY d.model_id, m.model_name, m.model_code ORDER BY cnt DESC
